import Image from "next/image";

// shadcn
import { Button } from "@/components/ui/button";

// constants
const products = [
  {
    name: "iPhone 11",
    price: "$700",
    image: "https://cdn.uiable.com/block/e-commerce9-1.jpg",
  },
  {
    name: "Nike AlphaDunk",
    price: "$180",
    image: "https://cdn.uiable.com/block/e-commerce9-2.jpg",
    featured: true,
  },
  {
    name: "Backpack",
    price: "$170",
    image: "https://cdn.uiable.com/block/e-commerce9-3.jpg",
  },
];

//  ------------------------------ | E - COMMERCE 9 | ------------------------------  //

export default function Ecommerce9() {
  return (
    <section className="py-20 lg:py-28">
      <div className="container mx-auto px-4">
        {/* Heading */}
        <div className="mx-auto mb-14 max-w-2xl text-center">
          <h2>Product You Need</h2>
          <p className="mt-4 text-muted-foreground">
            This is a big one and i consider it one of the most important things
            for a designer to get right.
          </p>
        </div>

        {/* Products Grid */}
        <div className="grid grid-cols-12 gap-6 items-stretch">
          {/* Left Card */}
          <div className="col-span-12 md:col-span-3">
            <div className="h-full rounded-3xl border p-6 flex flex-col items-center justify-between text-center min-h-96">
              <div className="flex justify-center pt-4">
                <Image
                  src={products[0].image}
                  alt={products[0].name}
                  width={140}
                  height={220}
                  className="h-auto w-auto object-contain"
                />
              </div>

              <div className="space-y-2 pb-4">
                <h5>{products[0].name}</h5>
                <p className="text-muted-foreground">{products[0].price}</p>
              </div>
            </div>
          </div>

          {/* Center Featured Card */}
          <div className="col-span-12 md:col-span-6">
            <div className="h-full rounded-3xl border p-6 min-h-96 flex flex-col justify-between">
              <div className="flex justify-center pt-2">
                <Image
                  src={products[1].image}
                  alt={products[1].name}
                  width={520}
                  height={260}
                  className="h-auto w-full max-w-lg object-contain"
                />
              </div>

              <div className="grid grid-cols-12 items-end gap-6 pt-4">
                <div className="col-span-12 sm:col-span-7">
                  <h5>{products[1].name}</h5>
                  <p className="mt-2 text-muted-foreground">
                    {products[1].price}
                  </p>
                </div>

                <div className="col-span-12 sm:col-span-5 sm:text-right">
                  <Button
                    size="lg"
                    className="bg-yellow-500 hover:bg-amber-400"
                  >
                    Add To Cart
                  </Button>
                </div>
              </div>
            </div>
          </div>

          {/* Right Card */}
          <div className="col-span-12 md:col-span-3">
            <div className="h-full rounded-3xl border bg-card p-6 flex flex-col items-center justify-between text-center min-h-96">
              <div className="flex justify-center pt-4">
                <Image
                  src={products[2].image}
                  alt={products[2].name}
                  width={180}
                  height={220}
                  className="h-auto w-auto object-contain"
                />
              </div>

              <div className="space-y-2 pb-4">
                <h5>{products[2].name}</h5>
                <p className="text-muted-foreground">{products[2].price}</p>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
